// === Klienten-Config & Normalisierung ===
// TODO: Beispiel-Map durch echten Store-Lookup ersetzen (Google Sheet / DB / n8n Data Table),
// gemappt ueber body.locationId. NIE Secrets im Klartext committen.
const body = $json.body || $json;
const CLIENTS = {
  "LOCATION_ID_BEISPIEL": { pit: "GHL_PIT_TOKEN", pixelId: "META_PIXEL_ID", capiToken: "META_CAPI_TOKEN", studioname: "Musterkueche" }
};
const locationId = body.locationId || "LOCATION_ID_BEISPIEL";
const cfg = CLIENTS[locationId] || CLIENTS["LOCATION_ID_BEISPIEL"];

const email = (body.email || "").trim().toLowerCase();
let phone = (body.phone || "").replace(/[^0-9]/g, "");
if (phone.startsWith("0")) phone = "49" + phone.slice(1); // DE-Laendercode

const fbclid = body.fbclid || "";
return [{ json: {
  locationId,
  pit: cfg.pit, pixelId: cfg.pixelId, capiToken: cfg.capiToken, studioname: cfg.studioname,
  name: body.name || "", email, emailNorm: email, phone, phoneNorm: phone,
  offer_typ: body.offer_typ || "", event_id: body.event_id || $execution.id,
  fbclid, fbc: fbclid ? ("fb.1." + Date.now() + "." + fbclid) : "", fbp: body.fbp || "",
  utm_source: body.utm_source || "", utm_campaign: body.utm_campaign || "", utm_medium: body.utm_medium || ""
}}];
